import urllib.request, json, re, time

def api(params):
    url = "https://en.wikipedia.org/w/api.php?" + "&".join(f"{k}={v}" for k,v in params.items())
    req = urllib.request.Request(url, headers={"User-Agent": "ResearchBot/1.0"})
    with urllib.request.urlopen(req, timeout=15) as r:
        return json.loads(r.read())

def get_last_june_rev(title):
    d = api({"action":"query","titles":title,"prop":"revisions","rvlimit":"50",
             "rvdir":"older","rvstart":"2023-07-01T00:00:00Z","rvend":"2023-05-01T00:00:00Z",
             "rvprop":"ids|timestamp","format":"json"})
    for p in d["query"]["pages"].values():
        revs = p.get("revisions",[])
        # Find the last one in June
        for rv in revs:
            if rv["timestamp"] >= "2023-06-01" and rv["timestamp"] < "2023-07-01":
                return rv["revid"], rv["timestamp"]
        # If no June edit, take the last edit before July (that was the June version)
        if revs:
            return revs[-1]["revid"], revs[-1]["timestamp"]
    return None, None

def get_wikitext(revid):
    d = api({"action":"query","revids":str(revid),"prop":"revisions",
             "rvprop":"content","format":"json"})
    for p in d["query"]["pages"].values():
        revs = p.get("revisions",[])
        if revs:
            return revs[0].get("*","")
    return ""

def count_twitter(text):
    refs = re.findall(r'<ref\b[^>]*>(.*?)</ref>', text, re.DOTALL|re.IGNORECASE)
    c = 0
    for r in refs:
        low = r.lower()
        if 'twitter.com' in low or 'x.com' in low:
            c += 1
    return c

total = 0
for day in range(1,32):
    title = f"August_{day}"
    rid, ts = get_last_june_rev(title)
    if rid:
        wt = get_wikitext(rid)
        c = count_twitter(wt)
        total += c
        print(f"Aug {day:2d}: revid={rid}, ts={ts[:10]}, twitter_refs={c}")
    else:
        print(f"Aug {day:2d}: NO REVISION FOUND")

print(f"\nTOTAL Twitter/X references across all 31 days: {total}")
